import{_ as o,o as a,c as t,au as r}from"./chunks/framework.Bpqx6pAq.js";const u=JSON.parse('{"title":"Query hooks","description":"","frontmatter":{},"headers":[],"relativePath":"api/core/hooks/hooks.query.md","filePath":"api/core/hooks/hooks.query.md"}'),c={name:"api/core/hooks/hooks.query.md"};function d(i,e,s,l,n,h){return a(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="query-hooks" tabindex="-1">Query hooks <a class="header-anchor" href="#query-hooks" aria-label="Permalink to &quot;Query hooks&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Hooks for transforming and marshalling query parameters before they reach the database adapter, and for populating related objects from other services into <code>hook.params</code>.</p><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="marshallcomparisonquery-hook" tabindex="-1"><code>marshallComparisonQuery(hook)</code> <a class="header-anchor" href="#marshallcomparisonquery-hook" aria-label="Permalink to &quot;`marshallComparisonQuery(hook)`&quot;">​</a></h3><p>Converts comparison field values in <code>hook.params.query</code> from client/server-side types (e.g. numbers as strings) to the correct JS types expected by the database adapter. Applies recursively to handle nested objects. Handles <code>$lt</code>, <code>$lte</code>, <code>$gt</code>, and <code>$gte</code> operators.</p><hr><h3 id="marshalltimequery-hook" tabindex="-1"><code>marshallTimeQuery(hook)</code> <a class="header-anchor" href="#marshalltimequery-hook" aria-label="Permalink to &quot;`marshallTimeQuery(hook)`&quot;">​</a></h3><p>Converts the <code>time</code> field in <code>hook.params.query</code> from string or moment date representations to the format expected by the database adapter.</p><hr><h3 id="marshallsortquery-hook" tabindex="-1"><code>marshallSortQuery(hook)</code> <a class="header-anchor" href="#marshallsortquery-hook" aria-label="Permalink to &quot;`marshallSortQuery(hook)`&quot;">​</a></h3><p>Converts <code>$sort</code> field values in <code>hook.params.query</code> from strings to numbers as required by the database adapter.</p><hr><h3 id="marshallcollationquery-hook" tabindex="-1"><code>marshallCollationQuery(hook)</code> <a class="header-anchor" href="#marshallcollationquery-hook" aria-label="Permalink to &quot;`marshallCollationQuery(hook)`&quot;">​</a></h3><p>Extracts MongoDB collation options from <code>hook.params.query</code>. Supports two shortcuts:</p><ul><li><code>$locale</code> — sets <code>hook.params.collation = { locale }</code> and removes the field from the query.</li><li><code>$collation</code> — sets <code>hook.params.collation</code> directly and removes the field from the query.</li></ul><hr><h3 id="marshallhttpquery-hook" tabindex="-1"><code>marshallHttpQuery(hook)</code> <a class="header-anchor" href="#marshallhttpquery-hook" aria-label="Permalink to &quot;`marshallHttpQuery(hook)`&quot;">​</a></h3><p>Converts query field values for REST (<code>provider === &#39;rest&#39;</code>) requests from strings to their correct JS types (numbers, booleans, dates). Only applied when the request comes from a REST client.</p><hr><h3 id="aggregationquery-hook" tabindex="-1"><code>aggregationQuery(hook)</code> <a class="header-anchor" href="#aggregationquery-hook" aria-label="Permalink to &quot;`aggregationQuery(hook)`&quot;">​</a></h3><blockquote><p>To be used as a <code>before</code> hook.</p></blockquote><p>Executes a raw MongoDB aggregation pipeline when <code>hook.params.query.$aggregation</code> is present and sets <code>hook.result</code> to bypass the normal service call. For security, aggregation is only allowed from internal (non-external-provider) calls.</p><hr><h3 id="populateobject-options" tabindex="-1"><code>populateObject(options)</code> <a class="header-anchor" href="#populateobject-options" aria-label="Permalink to &quot;`populateObject(options)`&quot;">​</a></h3><blockquote><p>Returns a hook function. To be used as a <code>before</code> hook.</p></blockquote><p>Retrieves a single object from a target service and stores it in <code>hook.params</code>. Skips population if the value is already present.</p><h4 id="options" tabindex="-1">Options <a class="header-anchor" href="#options" aria-label="Permalink to &quot;Options&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Option</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>serviceField</code></td><td>string</td><td>Path on <code>hook.data</code> or <code>hook.params.query</code> where the target service name is read</td></tr><tr><td><code>nameServiceAs</code></td><td>string</td><td>Path on <code>hook.params</code> where the resolved service is written (defaults to <code>serviceField</code>)</td></tr><tr><td><code>idField</code></td><td>string</td><td>Path on <code>hook.data</code> or <code>hook.params.query</code> where the target object ID is read</td></tr><tr><td><code>nameIdAs</code></td><td>string</td><td>Path on <code>hook.params</code> where the resolved object is written (defaults to <code>idField</code>)</td></tr><tr><td><code>throwOnNotFound</code></td><td>boolean</td><td>Throw an error if the service or object is not found</td></tr></tbody></table><hr><h3 id="unpopulateobject-options" tabindex="-1"><code>unpopulateObject(options)</code> <a class="header-anchor" href="#unpopulateobject-options" aria-label="Permalink to &quot;`unpopulateObject(options)`&quot;">​</a></h3><p>Removes a previously populated object and service from <code>hook.params</code>. Uses the same <code>nameIdAs</code>/<code>idField</code> and <code>nameServiceAs</code>/<code>serviceField</code> options as <code>populateObject</code>.</p><hr><h3 id="populateobjects-options" tabindex="-1"><code>populateObjects(options)</code> <a class="header-anchor" href="#populateobjects-options" aria-label="Permalink to &quot;`populateObjects(options)`&quot;">​</a></h3><blockquote><p>Returns a hook function. To be used as a <code>before</code> hook.</p></blockquote><p>Similar to <code>populateObject</code> but retrieves multiple objects. If no ID is provided, it fetches all objects from the target service via <code>service.find({ query: {} })</code>.</p><hr><h3 id="unpopulateobjects-options" tabindex="-1"><code>unpopulateObjects(options)</code> <a class="header-anchor" href="#unpopulateobjects-options" aria-label="Permalink to &quot;`unpopulateObjects(options)`&quot;">​</a></h3><p>Removes previously populated objects from <code>hook.params</code>. Behaves identically to <code>unpopulateObject</code>.</p><hr><h3 id="diacriticsearch-options" tabindex="-1"><code>diacriticSearch(options?)</code> <a class="header-anchor" href="#diacriticsearch-options" aria-label="Permalink to &quot;`diacriticSearch(options?)`&quot;">​</a></h3><blockquote><p>Returns a hook function.</p></blockquote><p>Transforms any <code>$regex</code> values in <code>hook.params.query</code> into diacritic-insensitive equivalents using <code>makeDiacriticPattern</code>. Operates recursively and is idempotent (won&#39;t transform the same regex twice).</p><hr><h3 id="todiacriticregex-object" tabindex="-1"><code>toDiacriticRegex(object)</code> <a class="header-anchor" href="#todiacriticregex-object" aria-label="Permalink to &quot;`toDiacriticRegex(object)`&quot;">​</a></h3><p>Utility function used internally by <code>diacriticSearch</code>. Recursively walks an object and replaces <code>$regex</code> values with their diacritic-insensitive counterparts.</p>',46)])])}const m=o(c,[["render",d]]);export{u as __pageData,m as default};
